payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "材料与硬件攻坚",
      "description": "完成仿生柔性传感器微结构设计、液态金属-聚氨酯复合材料制备及信号标定，构建0.1mm级空间分辨率的混合传感架构。"
    },
    {
      "date": "第3月",
      "title": "算法模型开发",
      "description": "训练分层CNN-LSTM手势识别模型，开发多模态融合协议栈，实现毫秒级实时推理与>98.2%的复杂工况识别准确率。"
    },
    {
      "date": "第4月",
      "title": "系统集成联调",
      "description": "嵌入压力/温度动态反馈执行单元，完成软硬件联调，构建感知-意图-反馈闭环，并接入H-Box全息舱等合作设备接口。"
    },
    {
      "date": "第5–6月",
      "title": "场景验证优化",
      "description": "在工业远程操控与虚拟实训等多场景开展压力测试，基于用户反馈迭代优化交互体验，形成可复用标准接口。"
    }
  ]
}

