payload.raw:
{
  "layout": "image-text",
  "title": "创新技术：基于智能数据手套的多模态人机交互系统",
  "subtitle": "",
  "body": [
    {
      "type": "paragraph",
      "text": "本系统构建“感知-意图-反馈”闭环模型，融合肌电信号、手指弯曲度与IMU数据，通过动态意图推理引擎实现高精度实时交互解析，解决传统系统模态割裂与意图误判问题。协议层采用自研轻量化通信协议，深度适配PICO、Unity中国版等国产XR生态，支持热插拔与跨平台加密传输，显著降低开发对接成本。全栈技术贯通自研传感器硬件、端侧轻量化融合算法与云端协同架构，形成软硬一体、开放可控的技术底座，相关成果已连续发表于ICASSP 2023与2024，被审稿人评价为‘为多模态交互提供可复现范式’。"
    }
  ],
  "image": {
    "prompt": "A detailed technical architecture diagram of a multimodal human-computer interaction system based on a smart data glove, showing signal flow from EMG, bend sensors, and IMU through edge computing to XR platforms like PICO and Unity China, with labeled modules for perception, intent inference, and feedback loop.",
    "alt": "智能数据手套多模态人机交互系统技术框架图，展示感知-意图-反馈闭环及与国产XR平台的集成"
  }
}

